    "wizard.usecase.medical.title":   "Türkçe tıbbi Soru-Cevap",
    "wizard.usecase.medical.badge":   "SFT",
    "wizard.usecase.medical.desc":    "Türkçe korpus üzerinde iki dilli tıbbi Soru-Cevap. Llama Guard güvenliği varsayılan açık.",
    "wizard.usecase.custom.title":    "Özel",
