    "wizard.judge.api_key_env.label": "API key env değişkeni",
    "wizard.judge.api_key_env.hint": "API anahtarını taşıyan ortam değişkeni adı. Boş = yerel judge modeli (API çağrısı yok).",
    "wizard.judge.min_score.label": "Minimum ortalama judge skoru",
